insert into books (id, title, author, isbn, page_count, published_date, description, cover_image_url, series_name, series_position) values
  ('a0000001-0000-0000-0000-000000000011', 'To Kill a Mockingbird', 'Harper Lee', '9780061120084', 281, '1960-07-11', 'The unforgettable novel of a childhood in a sleepy Southern town and the crisis of conscience that rocked it.', 'https://covers.openlibrary.org/b/isbn/9780061120084-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000012', 'The Hunger Games', 'Suzanne Collins', '9780439023481', 374, '2008-09-14', 'In the ruins of a place once known as North America lies the nation of Panem and its Capitol, which forces children to fight to the death in the annual Hunger Games.', 'https://covers.openlibrary.org/b/isbn/9780439023481-L.jpg', 'The Hunger Games', 1),
  ('a0000001-0000-0000-0000-000000000013', 'The Girl with the Dragon Tattoo', 'Stieg Larsson', '9780307454546', 465, '2005-08-01', 'Journalist Mikael Blomkvist and hacker Lisbeth Salander investigate the disappearance of a wealthy patriarch''s niece from forty years ago.', 'https://covers.openlibrary.org/b/isbn/9780307454546-L.jpg', 'Millennium', 1),
  ('a0000001-0000-0000-0000-000000000014', 'Fight Club', 'Chuck Palahniuk', '9780393327342', 208, '1996-08-17', 'An insomniac office worker and a devil-may-care soap maker form an underground fight club that evolves into much more.', 'https://covers.openlibrary.org/b/isbn/9780393327342-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000015', 'The Godfather', 'Mario Puzo', '9780451205766', 448, '1969-03-10', 'The aging patriarch of an organized crime dynasty transfers control of his empire to his reluctant youngest son.', 'https://covers.openlibrary.org/b/isbn/9780451205766-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000016', 'Jurassic Park', 'Michael Crichton', '9780345538987', 448, '1990-11-20', 'A billionaire creates a theme park of cloned dinosaurs on a remote island, but the park''s security systems fail catastrophically.', 'https://covers.openlibrary.org/b/isbn/9780345538987-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000017', 'The Silence of the Lambs', 'Thomas Harris', '9780312924584', 338, '1988-05-01', 'FBI trainee Clarice Starling is assigned to interview imprisoned cannibalistic serial killer Hannibal Lecter to gain his insight into an active case.', 'https://covers.openlibrary.org/b/isbn/9780312924584-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000018', 'Little Women', 'Louisa May Alcott', '9780147514011', 449, '1868-09-30', 'The story of the March sisters — Meg, Jo, Beth, and Amy — as they grow from childhood to adulthood in Civil War-era America.', 'https://covers.openlibrary.org/b/isbn/9780147514011-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000019', 'The Martian', 'Andy Weir', '9780553418026', 369, '2011-01-01', 'Astronaut Mark Watney is stranded alone on Mars after his crew evacuates, presuming him dead. He must use his ingenuity to survive.', 'https://covers.openlibrary.org/b/isbn/9780553418026-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000020', 'Call Me by Your Name', 'Andre Aciman', '9780312426781', 248, '2007-01-23', 'A seventeen-year-old boy growing up in 1980s Italy discovers desire when a visiting scholar arrives at his family''s villa.', 'https://covers.openlibrary.org/b/isbn/9780312426781-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000021', 'The Revenant', 'Michael Punke', '9781250101198', 272, '2002-01-01', 'The true story of frontiersman Hugh Glass, who was mauled by a grizzly bear and left for dead by his companions.', 'https://covers.openlibrary.org/b/isbn/9781250101198-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000022', 'Pride and Prejudice', 'Jane Austen', '9780141439518', 279, '1813-01-28', 'The story of Elizabeth Bennet and Mr Darcy, navigating manners, morality, and misunderstandings in Regency-era England.', 'https://covers.openlibrary.org/b/isbn/9780141439518-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000023', 'The Talented Mr. Ripley', 'Patricia Highsmith', '9780393332148', 287, '1955-01-01', 'Tom Ripley travels to Italy to retrieve a wealthy man''s son, but becomes obsessed with the young man''s luxurious lifestyle.', 'https://covers.openlibrary.org/b/isbn/9780393332148-L.jpg', 'Ripley', 1),
  ('a0000001-0000-0000-0000-000000000024', 'Atonement', 'Ian McEwan', '9780099429791', 351, '2001-09-01', 'On a hot summer day in 1935, thirteen-year-old Briony Tallis witnesses a moment between her older sister and the son of a servant — and commits a crime that will change all their lives.', 'https://covers.openlibrary.org/b/isbn/9780099429791-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000025', 'The Road', 'Cormac McCarthy', '9780307387899', 287, '2006-09-26', 'A father and his young son walk alone through a burned and destroyed America, heading towards the coast in a post-apocalyptic world.', 'https://covers.openlibrary.org/b/isbn/9780307387899-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000026', 'Trainspotting', 'Irvine Welsh', '9780393314809', 344, '1993-01-01', 'The story of a group of heroin addicts in Edinburgh, Scotland, and their passage through the rites of substance abuse.', 'https://covers.openlibrary.org/b/isbn/9780393314809-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000027', 'The Perks of Being a Wallflower', 'Stephen Chbosky', '9781451696196', 213, '1999-02-01', 'Charlie, a shy and introspective teenager, navigates his first year of high school with the help of two charismatic seniors.', 'https://covers.openlibrary.org/b/isbn/9781451696196-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000028', 'Crazy Rich Asians', 'Kevin Kwan', '9780385536974', 403, '2013-06-11', 'When Rachel Chu agrees to spend the summer in Singapore with her boyfriend Nick Young, she discovers his family is one of the wealthiest in Asia.', 'https://covers.openlibrary.org/b/isbn/9780385536974-L.jpg', 'Crazy Rich Asians', 1),
  ('a0000001-0000-0000-0000-000000000029', 'The Color Purple', 'Alice Walker', '9780156028356', 295, '1982-06-01', 'The deeply moving story of Celie, a young African American woman growing up in the rural South, told through her letters to God and her sister.', 'https://covers.openlibrary.org/b/isbn/9780156028356-L.jpg', null, null),
  ('a0000001-0000-0000-0000-000000000030', 'Where the Crawdads Sing', 'Delia Owens', '9780735219090', 368, '2018-08-14', 'Kya Clark, the so-called Marsh Girl, is abandoned by her family and grows up alone in the marshes of North Carolina. When a popular local is found dead, she becomes the prime suspect.', 'https://covers.openlibrary.org/b/isbn/9780735219090-L.jpg', null, null);
insert into screen_media (id, title, type, director, synopsis, release_date, poster_url, tmdb_id, runtime_minutes, seasons_count) values
  ('c0000001-0000-0000-0000-000000000012', 'To Kill a Mockingbird', 'film', 'Robert Mulligan', 'Atticus Finch, a lawyer in the Depression-era South, defends a Black man against an undeserved charge while his children learn about justice.', '1962-12-25', 'https://image.tmdb.org/t/p/w500/gSl0RbpGVQjqDOyPEJxsPhSBGAB.jpg', 938, 129, null),
  ('c0000001-0000-0000-0000-000000000013', 'The Hunger Games', 'film', 'Gary Ross', 'Katniss Everdeen voluntarily takes her younger sister''s place in the Hunger Games, a televised fight to the death.', '2012-03-23', 'https://image.tmdb.org/t/p/w500/yDSPwJjNzEMiOiPqTp3OPdrMI6k.jpg', 70160, 142, null),
  ('c0000001-0000-0000-0000-000000000014', 'The Girl with the Dragon Tattoo', 'film', 'David Fincher', 'Journalist Mikael Blomkvist is aided in his search for a woman who has been missing for forty years by Lisbeth Salander, a young computer hacker.', '2011-12-21', 'https://image.tmdb.org/t/p/w500/xyMxjJtaHMfpGKiIlmCH1HHBzY8.jpg', 65754, 158, null),
  ('c0000001-0000-0000-0000-000000000015', 'Fight Club', 'film', 'David Fincher', 'An insomniac office worker and a devil-may-care soap maker form an underground fight club.', '1999-10-15', 'https://image.tmdb.org/t/p/w500/pB8BM7pdSp6B6Ih7QI4S2t0POD5.jpg', 550, 139, null),
  ('c0000001-0000-0000-0000-000000000016', 'The Godfather', 'film', 'Francis Ford Coppola', 'The aging patriarch of an organized crime dynasty transfers control of his clandestine empire to his reluctant youngest son.', '1972-03-15', 'https://image.tmdb.org/t/p/w500/3bhkrj58Vtu7enYsRolD1fZdja1.jpg', 238, 175, null),
  ('c0000001-0000-0000-0000-000000000017', 'Jurassic Park', 'film', 'Steven Spielberg', 'A pragmatic paleontologist visiting a theme park populated with cloned dinosaurs is tasked with protecting a couple of kids after the park''s power fails.', '1993-06-11', 'https://image.tmdb.org/t/p/w500/oU7Oez2kCnRzjpgkiu7kOa3Pn6V.jpg', 329, 127, null),
  ('c0000001-0000-0000-0000-000000000018', 'The Silence of the Lambs', 'film', 'Jonathan Demme', 'A young FBI cadet must receive the help of an incarcerated and manipulative cannibal killer to help catch another serial killer.', '1991-02-14', 'https://image.tmdb.org/t/p/w500/rplLJ2hPcOQmkFhTqUte0MkEb9a.jpg', 274, 118, null),
  ('c0000001-0000-0000-0000-000000000019', 'Little Women', 'film', 'Greta Gerwig', 'Four sisters come of age in America in the aftermath of the Civil War. Jo March reflects on her life in a story of family and independence.', '2019-12-25', 'https://image.tmdb.org/t/p/w500/yn5ihODtZ7ofn8pDYfxCmxh8AXI.jpg', 331482, 135, null),
  ('c0000001-0000-0000-0000-000000000020', 'The Martian', 'film', 'Ridley Scott', 'An astronaut becomes stranded on Mars and must find a way to signal to Earth that he is alive and devise a plan to survive.', '2015-10-02', 'https://image.tmdb.org/t/p/w500/5BHuvQ6p9kfc091Z8RiFNhCwL4b.jpg', 286217, 144, null),
  ('c0000001-0000-0000-0000-000000000021', 'Call Me by Your Name', 'film', 'Luca Guadagnino', 'In 1980s Italy, a romance blossoms between a seventeen-year-old student and the older man his academic father has hired as a summer research assistant.', '2017-11-24', 'https://image.tmdb.org/t/p/w500/nPTjj6ZfBXXBwOhd7iN3XNe2EM3.jpg', 398818, 132, null),
  ('c0000001-0000-0000-0000-000000000022', 'The Revenant', 'film', 'Alejandro Gonzalez Inarritu', 'A frontiersman on a fur trading expedition in the 1820s fights for survival after being mauled by a bear and left for dead by his hunting team.', '2015-12-25', 'https://image.tmdb.org/t/p/w500/ji3ecJphATlVgWNY0B4gCN7jMBg.jpg', 281957, 156, null),
  ('c0000001-0000-0000-0000-000000000023', 'Pride and Prejudice', 'film', 'Joe Wright', 'A spirited young woman meets her match in the proud Mr Darcy, and must overcome her own prejudices to find true love.', '2005-11-11', 'https://image.tmdb.org/t/p/w500/sOlkWV3rLKiyUhPOF9q6o6BV9ql.jpg', 4348, 129, null),
  ('c0000001-0000-0000-0000-000000000024', 'The Talented Mr. Ripley', 'film', 'Anthony Minghella', 'In late 1950s New York, Tom Ripley is sent to Italy to retrieve a wealthy man''s playboy son, but becomes obsessed with his lifestyle.', '1999-12-25', 'https://image.tmdb.org/t/p/w500/6cpVCI4v70bRJ8joERuQQP7ibre.jpg', 1213, 139, null),
  ('c0000001-0000-0000-0000-000000000025', 'Atonement', 'film', 'Joe Wright', 'Thirteen-year-old Briony Tallis irrevocably changes the lives of three people when she accuses her older sister''s lover of a crime he did not commit.', '2007-09-07', 'https://image.tmdb.org/t/p/w500/iiEPnXXnMRUdGCkDBYVFig3beaP.jpg', 4347, 123, null),
  ('c0000001-0000-0000-0000-000000000026', 'The Road', 'film', 'John Hillcoat', 'A father and his son walk alone through burned America, heading through the ravaged landscape to the coast.', '2009-11-25', 'https://image.tmdb.org/t/p/w500/se5Hxz7PArQZOG3Nx2bpfOhLhtV.jpg', 14514, 111, null),
  ('c0000001-0000-0000-0000-000000000027', 'Trainspotting', 'film', 'Danny Boyle', 'Renton attempts to give up heroin with the encouragement of his friends but the allure of the drug and the influence of others keep pulling him back.', '1996-02-23', 'https://image.tmdb.org/t/p/w500/p0GKbRSgiMwkEwnRBaTeNkp3voo.jpg', 627, 94, null),
  ('c0000001-0000-0000-0000-000000000028', 'The Perks of Being a Wallflower', 'film', 'Stephen Chbosky', 'An introvert freshman is taken under the wings of two seniors who welcome him to the real world.', '2012-09-21', 'https://image.tmdb.org/t/p/w500/aKBfTJD7YviQ6s9griGIoRKaEoF.jpg', 84892, 103, null),
  ('c0000001-0000-0000-0000-000000000029', 'Crazy Rich Asians', 'film', 'Jon M. Chu', 'Rachel Chu accompanies her boyfriend to his best friend''s wedding in Singapore and is stunned to learn that his family is extremely wealthy.', '2018-08-15', 'https://image.tmdb.org/t/p/w500/1XxL4LJ5WHdrcYcihEZUCgNCpAW.jpg', 455207, 120, null),
  ('c0000001-0000-0000-0000-000000000030', 'The Color Purple', 'film', 'Steven Spielberg', 'A woman named Celie survives unimaginable abuse and bigotry in the American South and ultimately finds extraordinary strength through deep bonds of sisterhood.', '1985-12-18', 'https://image.tmdb.org/t/p/w500/bm3OVZMdqJMEQO5WKXB3c22YfDl.jpg', 873, 154, null),
  ('c0000001-0000-0000-0000-000000000031', 'Where the Crawdads Sing', 'film', 'Olivia Newman', 'A woman who raised herself in the marshes of the deep South becomes a suspect in the murder of a man she was once involved with.', '2022-07-15', 'https://image.tmdb.org/t/p/w500/isMgoUZqJSMVkPAMiI9WKGP6x1N.jpg', 850165, 125, null);
insert into adaptations (book_id, screen_media_id, adaptation_type, release_year, notes) values
  ('a0000001-0000-0000-0000-000000000011', 'c0000001-0000-0000-0000-000000000012', 'film', 1962, 'Academy Award-winning adaptation with Gregory Peck'),
  ('a0000001-0000-0000-0000-000000000012', 'c0000001-0000-0000-0000-000000000013', 'film', 2012, 'First film in the franchise starring Jennifer Lawrence'),
  ('a0000001-0000-0000-0000-000000000013', 'c0000001-0000-0000-0000-000000000014', 'film', 2011, 'David Fincher''s American adaptation starring Daniel Craig'),
  ('a0000001-0000-0000-0000-000000000014', 'c0000001-0000-0000-0000-000000000015', 'film', 1999, 'David Fincher''s cult classic with Brad Pitt and Edward Norton'),
  ('a0000001-0000-0000-0000-000000000015', 'c0000001-0000-0000-0000-000000000016', 'film', 1972, 'Widely regarded as one of the greatest films ever made'),
  ('a0000001-0000-0000-0000-000000000016', 'c0000001-0000-0000-0000-000000000017', 'film', 1993, 'Spielberg''s groundbreaking blockbuster that revolutionised visual effects'),
  ('a0000001-0000-0000-0000-000000000017', 'c0000001-0000-0000-0000-000000000018', 'film', 1991, 'Swept all five major Academy Awards'),
  ('a0000001-0000-0000-0000-000000000018', 'c0000001-0000-0000-0000-000000000019', 'film', 2019, 'Greta Gerwig''s acclaimed adaptation with Saoirse Ronan'),
  ('a0000001-0000-0000-0000-000000000019', 'c0000001-0000-0000-0000-000000000020', 'film', 2015, 'Ridley Scott''s hit starring Matt Damon'),
  ('a0000001-0000-0000-0000-000000000020', 'c0000001-0000-0000-0000-000000000021', 'film', 2017, 'Luca Guadagnino''s award-winning adaptation'),
  ('a0000001-0000-0000-0000-000000000021', 'c0000001-0000-0000-0000-000000000022', 'film', 2015, 'Won Leonardo DiCaprio his first Academy Award for Best Actor'),
  ('a0000001-0000-0000-0000-000000000022', 'c0000001-0000-0000-0000-000000000023', 'film', 2005, 'Joe Wright''s adaptation starring Keira Knightley and Matthew Macfadyen'),
  ('a0000001-0000-0000-0000-000000000023', 'c0000001-0000-0000-0000-000000000024', 'film', 1999, 'Anthony Minghella''s psychological thriller with Matt Damon and Jude Law'),
  ('a0000001-0000-0000-0000-000000000024', 'c0000001-0000-0000-0000-000000000025', 'film', 2007, 'Joe Wright''s sweeping period drama starring James McAvoy and Keira Knightley'),
  ('a0000001-0000-0000-0000-000000000025', 'c0000001-0000-0000-0000-000000000026', 'film', 2009, 'John Hillcoat''s bleak adaptation starring Viggo Mortensen'),
  ('a0000001-0000-0000-0000-000000000026', 'c0000001-0000-0000-0000-000000000027', 'film', 1996, 'Danny Boyle''s iconic British film starring Ewan McGregor'),
  ('a0000001-0000-0000-0000-000000000027', 'c0000001-0000-0000-0000-000000000028', 'film', 2012, 'Directed by the novel''s author Stephen Chbosky'),
  ('a0000001-0000-0000-0000-000000000028', 'c0000001-0000-0000-0000-000000000029', 'film', 2018, 'First major Hollywood film with an all-Asian cast in 25 years'),
  ('a0000001-0000-0000-0000-000000000029', 'c0000001-0000-0000-0000-000000000030', 'film', 1985, 'Steven Spielberg''s adaptation starring Whoopi Goldberg and Oprah Winfrey'),
  ('a0000001-0000-0000-0000-000000000030', 'c0000001-0000-0000-0000-000000000031', 'film', 2022, 'Film adaptation produced by Reese Witherspoon''s production company');
